options.styles:
* {
  box-sizing: border-box;
  margin: 0;
  padding: 0
}

@keyframes shimmer {
  0% {
    background-position: 200% 0
  }

  100% {
    background-position: -200% 0
  }
}

@keyframes fade-in {
  from {
    opacity: 0;
    transform: translateY(4px)
  }

  to {
    opacity: 1;
    transform: translateY(0)
  }
}

@keyframes glow-pulse {

  0%,
  100% {
    opacity: .3
  }

  50% {
    opacity: .7
  }
}

@keyframes stale-flash {

  0%,
  100% {
    opacity: .6
  }

  50% {
    opacity: 1
  }
}

.p {
  background: #0d1117;
  color: #e6edf3;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  border-radius: 10px;
  width: 100%;
  height: 100%;
  padding: 10px 16px;
  display: grid;
  grid-template-columns: 1fr 180px 1fr;
  gap: 0;
  align-items: stretch;
  overflow: hidden;
  position: relative;
  border: 1px solid rgba(66, 133, 244, .08);
  box-shadow: 0 4px 24px rgba(0, 0, 0, .4), inset 0 1px 0 rgba(255, 255, 255, .03)
}

.p::before {
  content: "";
  position: absolute;
  top: 0;
  left: 20px;
  right: 20px;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(90, 157, 247, .4) 30%, rgba(51, 204, 232, .4) 50%, rgba(143, 212, 126, .4) 70%, transparent);
  z-index: 2
}

.p::after {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: radial-gradient(ellipse 70% 50% at 50% 0%, rgba(66, 133, 244, .04) 0%, transparent 70%);
  pointer-events: none;
  z-index: 0
}

.p>* {
  position: relative;
  z-index: 1
}

.lb {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1.5px;
  text-transform: uppercase;
  color: rgba(180, 210, 255, .5);
  display: block;
  margin-bottom: 1px
}

.vl {
  font-family: "SF Mono", "Fira Code", ui-monospace, monospace;
  font-variant-numeric: tabular-nums;
  font-weight: 700;
  line-height: 1.15
}

.sl {
  font-size: 9px;
  font-weight: 700;
  letter-spacing: 2px;
  text-transform: uppercase;
  color: rgba(180, 210, 255, .4);
  padding-bottom: 3px;
  margin-bottom: 4px;
  border-bottom: 1px solid rgba(255, 255, 255, .05);
  display: block
}

.badge {
  padding: 4px 0;
  border-radius: 5px;
  font-size: 11px;
  font-weight: 800;
  letter-spacing: 1px;
  text-transform: uppercase;
  text-align: center;
  display: block;
  width: 100%;
  transition: all .4s ease
}

.bg {
  background: rgba(107, 114, 128, .2);
  color: #b0b5bd;
  border: 1px solid rgba(107, 114, 128, .3)
}

.bb {
  background: rgba(66, 133, 244, .15);
  color: #6CA6F7;
  border: 1px solid rgba(66, 133, 244, .25);
  box-shadow: 0 0 12px rgba(66, 133, 244, .12)
}

.bgr {
  background: rgba(115, 191, 105, .15);
  color: #8FD47E;
  border: 1px solid rgba(115, 191, 105, .25);
  box-shadow: 0 0 12px rgba(115, 191, 105, .12)
}

.by {
  background: rgba(250, 222, 42, .15);
  color: #FFE650;
  border: 1px solid rgba(250, 222, 42, .25);
  box-shadow: 0 0 12px rgba(250, 222, 42, .12)
}

.br {
  background: rgba(242, 73, 92, .15);
  color: #F56B7A;
  border: 1px solid rgba(242, 73, 92, .25);
  box-shadow: 0 0 12px rgba(242, 73, 92, .12)
}

.pill {
  border-radius: 6px;
  padding: 3px 7px;
  text-align: center;
  display: inline-flex;
  flex-direction: column;
  gap: 0;
  flex-shrink: 0;
  transition: transform .2s ease, box-shadow .3s ease
}

.pill:hover {
  transform: translateY(-1px);
  box-shadow: 0 3px 12px rgba(0, 0, 0, .4), 0 0 8px rgba(66, 133, 244, .1)
}

.epb {
  height: 5px;
  background: rgba(255, 255, 255, .06);
  border-radius: 3px;
  margin-top: 3px;
  overflow: hidden;
  border: 1px solid rgba(255, 255, 255, .04)
}

.epf {
  height: 100%;
  border-radius: 2px;
  background: linear-gradient(90deg, #5A9DF7, #33CCE8, #8FD47E);
  transition: width .8s cubic-bezier(.22, 1, .36, 1);
  box-shadow: 0 0 10px rgba(66, 133, 244, .35)
}

.bt {
  height: 12px;
  background: rgba(255, 255, 255, .06);
  border-radius: 4px;
  overflow: hidden;
  flex: 1;
  border: 1px solid rgba(255, 255, 255, .04)
}

.bf {
  height: 100%;
  border-radius: 3px;
  transition: width .6s cubic-bezier(.22, 1, .36, 1);
  box-shadow: 0 0 8px rgba(66, 133, 244, .2)
}

.kbt {
  height: 5px;
  background: rgba(255, 255, 255, .05);
  border-radius: 3px;
  overflow: hidden;
  flex: 1
}

.kbf {
  height: 100%;
  border-radius: 3px;
  transition: width .6s cubic-bezier(.22, 1, .36, 1)
}

.dv {
  width: 1px;
  background: rgba(255, 255, 255, .06);
  align-self: stretch;
  flex-shrink: 0
}

.dh {
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(255, 255, 255, .06), transparent);
  margin: 3px 0
}

.stale-banner {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  background: linear-gradient(90deg, rgba(242, 73, 92, .15), rgba(242, 73, 92, .08));
  border-bottom: 1px solid rgba(242, 73, 92, .2);
  color: #F2495C;
  font-size: 10px;
  font-weight: 800;
  letter-spacing: 2px;
  text-transform: uppercase;
  text-align: center;
  padding: 3px 0;
  z-index: 10;
  animation: stale-flash 2s ease-in-out infinite;
  display: none
}

.spark-wrap {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
  background: rgba(255, 255, 255, .015);
  border-radius: 4px;
  padding: 2px 4px;
  border: 1px solid rgba(255, 255, 255, .03);
  transition: border-color .3s
}

.spark-wrap:hover {
  border-color: rgba(255, 255, 255, .08)
}

.val-flash {
  animation: fade-in .3s ease-out
}

.copy-toast {
  position: absolute;
  bottom: 8px;
  left: 50%;
  transform: translateX(-50%) translateY(10px);
  background: rgba(30, 38, 50, .95);
  color: #8FD47E;
  font-family: "SF Mono", "Fira Code", ui-monospace, monospace;
  font-size: 12px;
  font-weight: 700;
  padding: 8px 16px;
  border-radius: 6px;
  border: 1px solid rgba(115, 191, 105, .25);
  box-shadow: 0 4px 16px rgba(0, 0, 0, .4), 0 0 12px rgba(115, 191, 105, .1);
  opacity: 0;
  transition: opacity .3s, transform .3s;
  pointer-events: none;
  z-index: 100
}

.copy-toast.show {
  opacity: 1;
  transform: translateX(-50%) translateY(0)
}

#spark-bars {
  cursor: pointer
}

.dt-row {
  overflow: hidden !important;
  height: 100% !important
}

.dt-row::-webkit-scrollbar {
  display: none
}

.dt-row>div {
  height: 100% !important
}
